#include <stdio.h>
#define MOD 1000000007LL
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int n,m; scanf("%d %d",&n,&m);
        long long ans=0;
        if(n==1 && m==0) ans=1;
        else if(n==2 && m==1) ans=1;
        else if(n==3 && m==3) ans=1;
        else if(n==4){
            if(m==4) ans=3;
            else if(m==5) ans=6;
            else if(m==6) ans=1;
        }
        printf("%lld\n", ans%MOD);
    }
    return 0;
}

